import React, { useState } from 'react';

function InputForm() {
  const [name, setName] = useState('');
  const handleChange = (event) => {
    setName(event.target.value);
  };
  const handleSubmit = () => {
    alert(`Ad: ${name}`);
  };
  return (
    <div>
      <input type="text" value={name} onChange={handleChange} placeholder="Adınızı daxil edin" />
      <button onClick={handleSubmit}>Göndər</button>
      <p>Daxil edilən ad: {name}</p>
    </div>
  );
}

